SELECT Vendor.No_ AS VendorNo_, Vendor.Name AS VendorName, Item.[Trademark Code], Item.[Season Code], Item.[line code], Item.[collection code], Item.[product sex], Item.[product family], [VendutoCompratoProiezione-step11-new-calcoli].No_, Item.Description, Item.[Description 2], [VendutoCompratoProiezione-step11-new-calcoli].[Constant Variable Code] AS ColorCode, [Variable Code].Description AS Color, [VendutoCompratoProiezione-step11-new-calcoli].PairsSold, [VendutoCompratoProiezione-step11-new-calcoli].PairsPurchased, [VendutoCompratoProiezione-step11-new-calcoli].PairsInventory, [VendutoCompratoProiezione-step11-new-calcoli].toBuy, [VendutoCompratoProiezione-step11-new-calcoli].toSell, [VendutoCompratoProiezione-step11-new-calcoli].ForecastedPairsByMarket_, [VendutoCompratoProiezione-step11-new-calcoli].ForecastedPairsByMarketCorrected_, [VendutoCompratoProiezione-step11-new-calcoli].toBuyByBudgetCorrected, [VendutoCompratoProiezione-step11-new-calcoli].toSellByBudgetCorrected, [VendutoCompratoProiezione-step11-new-calcoli].ForecastedPairsFlat, [VendutoCompratoProiezione-step11-new-calcoli].toBuyFlat, [VendutoCompratoProiezione-step11-new-calcoli].toSellFlat, [VendutoCompratoProiezione-Vendite-step2-CalcoloIncidenzeCliente].Incidenza, [VendutoCompratoProiezione-Vendite-step2-CalcoloIncidenzeCliente].[Bill-to Customer No_], [VendutoCompratoProiezione-Vendite-step2-CalcoloIncidenzeCliente].[Bill-to Name], [VendutoCompratoProiezione-Vendite-step2-CalcoloIncidenzeCliente].PairsSold_, Immagini.[Linked Document], DatiCarryOverESMU.[Potential Sold Out], DatiCarryOverESMU.[Sold Out], Item.Manufacturer, Vendor_1.Name AS ManufacturerName, DatiCarryOverESMU.[Carry Over], DatiCarryOverESMU.MOQ, IIf([ForecastedPairsByMarketCorrected_]>0.95*[MOQ]," * * *",IIf([ForecastedPairsByMarketCorrected_]>0.8*[MOQ]," * * ",IIf([ForecastedPairsByMarketCorrected_]>0.6*[MOQ]," * ","X"))) AS testMOQ
FROM ((((((Item RIGHT JOIN [VendutoCompratoProiezione-step11-new-calcoli] ON Item.No_ = [VendutoCompratoProiezione-step11-new-calcoli].No_) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) LEFT JOIN [VendutoCompratoProiezione-Vendite-step2-CalcoloIncidenzeCliente] ON ([VendutoCompratoProiezione-step11-new-calcoli].No_ = [VendutoCompratoProiezione-Vendite-step2-CalcoloIncidenzeCliente].No_) AND ([VendutoCompratoProiezione-step11-new-calcoli].[Constant Variable Code] = [VendutoCompratoProiezione-Vendite-step2-CalcoloIncidenzeCliente].[Constant Variable Code])) LEFT JOIN [Variable Code] ON (Item.[Variable Group 01] = [Variable Code].[Variable Group]) AND (Item.[Variable Code 01] = [Variable Code].[Variable Code])) LEFT JOIN Immagini ON ([VendutoCompratoProiezione-step11-new-calcoli].No_ = Immagini.[Source No_]) AND ([VendutoCompratoProiezione-step11-new-calcoli].[Constant Variable Code] = Immagini.[Constant Variable Code])) LEFT JOIN DatiCarryOverESMU ON ([VendutoCompratoProiezione-step11-new-calcoli].No_ = DatiCarryOverESMU.[Model Item No_]) AND ([VendutoCompratoProiezione-step11-new-calcoli].[Constant Variable Code] = DatiCarryOverESMU.[Variable Code 01])) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_;

